          sourceSnippet: "Encyclopaedia Britannica — 古希腊的民主",
          source2: "World History Encyclopedia",
          sourceUrl2: "https://www.worldhistory.org/Athenian_Democracy/",
          sourceSnippet2: "World History Encyclopedia — 雅典民主制"
